import datetime

def compute_team_charge(
    team_id: str,
    month: str,
    usage: dict[str, dict[str, int]],   # {service_name: {token_type: count}}
    rate_card: list,                     # list of RateCardEntry objects
) -> dict:
    """
    Compute a team's monthly internal charge from raw token usage.
    usage example: {"standard": {"input": 1_200_000, "output": 300_000}}
    """
    rates = {e.service_name: e for e in rate_card}
    line_items = []
    total = 0.0

    for service, tokens in usage.items():
        if service not in rates:
            continue
        entry = rates[service]
        for token_type, count in tokens.items():
            unit_price = entry.internal_price(token_type)
            cost = count / 1_000_000 * unit_price
            total += cost
            line_items.append({
                "service": service,
                "token_type": token_type,
                "tokens": count,
                "unit_price_per_M": round(unit_price, 4),
                "charge_usd": round(cost, 4),
            })

    return {
        "team_id": team_id,
        "month": month,
        "line_items": line_items,
        "total_charge_usd": round(total, 4),
        "generated_at": datetime.datetime.utcnow().isoformat(),
    }


# Example: Platform Engineering team usage in July 2025
usage = {
    "standard":  {"input": 800_000_000, "output": 200_000_000},
    "optimized": {"input": 400_000_000, "cache_write": 50_000_000, "cache_read": 350_000_000, "output": 80_000_000},
    "haiku":     {"input": 2_000_000_000, "output": 500_000_000},
}

from gen_rate_card import RATE_CARD  # import the rate card defined above
charge = compute_team_charge("platform-eng", "2025-07", usage, RATE_CARD)
print(f"Team: {charge['team_id']}  Month: {charge['month']}")
print(f"Total charge: ${charge['total_charge_usd']:,.2f}")
for li in charge["line_items"]:
    print(f"  {li['service']}/{li['token_type']}: {li['tokens']:,} tokens @ ${li['unit_price_per_M']}/M = ${li['charge_usd']:,.2f}")
